import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract_packages(data):
    result = {}
    for project in data.get('projects', []):
        pname = project['path'].split('/')[-1]
        pkgs = {}
        for fw in project.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (pkg['id'], fw['framework'])
                pkgs[key] = pkg.get('resolvedVersion', pkg.get('requestedVersion', ''))
        result[pname] = pkgs
    return result

b = extract_packages(baseline)
a = extract_packages(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for key in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(key, 'N/A')
        av = ap.get(key, 'N/A')
        if bv != av:
            changes = True
            print(f'  {proj}: {key[0]} ({key[1]}): {bv} -> {av}')

if not changes:
    print('  No version changes detected')

print()
print('=== UNCHANGED (sample) ===')
count = 0
for proj in sorted(b.keys()):
    for key in sorted(b.get(proj, {}).keys()):
        bv = b[proj][key]
        av = a.get(proj, {}).get(key, '')
        if bv == av:
            count += 1
if count > 0:
    print(f'  {count} package-framework combinations unchanged')
"

